'use client';

import { QueryObserverResult, RefetchOptions } from '@tanstack/react-query';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { useForm, Controller } from 'react-hook-form';
import { toast } from 'react-toastify';

import {
  usePatchAgreeDocStatus,
  usePatchArrivedStatus,
  usePatchCompetencyScore,
  usePatchInterviewScore,
  usePatchOneseoApproval,
} from '@repo/api/hooks';
import { useDebounce } from '@repo/hooks';
import { useModalStore } from '@repo/store';
import { EditabilityType, OneseoListType, OneseoType, ScreeningEnum } from '@repo/types';
import { CheckIcon } from '@repo/ui/icons';
import { Badge, Button, TableCell, TableRow, Toggle } from '@repo/ui/shadcn';
import { cn, formatScore } from '@repo/utils';

import { SideBarType } from '@/schemas';

import TextField from '../TextField';

interface ApplicationTRProps extends OneseoType {
  editableData: EditabilityType | undefined;
  oneseoRefetch: (
    options?: RefetchOptions | undefined,
  ) => Promise<QueryObserverResult<OneseoListType, Error>>;
  editableRefetch: (
    options?: RefetchOptions | undefined,
  ) => Promise<QueryObserverResult<EditabilityType, Error>>;
  is역량검사처리기간: boolean;
  is심층면접처리기간: boolean;
  testResultTag: SideBarType;
}

const ApplicantTR = ({
  oneseoRefetch,
  competencyEvaluationScore,
  firstTestPassYn,
  interviewScore,
  memberId,
  name,
  phoneNumber,
  realOneseoArrivedYn,
  schoolName,
  screening,
  secondTestPassYn,
  submitCode,
  entranceIntentionYn,
  editableData,
  editableRefetch,
  is역량검사처리기간,
  is심층면접처리기간,
  oneseoEditStatus,
  testResultTag,
}: ApplicationTRProps) => {
  const {
    setDocumentSubmissionChangeModal,
    setAdmissionAgreementChangeModal,
    setApplicationModificationNotPossibleModal,
  } = useModalStore();

  const { push } = useRouter();

  const [isRealOneseoArrived, setIsRealOneseoArrived] = useState<boolean>(
    realOneseoArrivedYn === 'YES',
  );
  const [entranceIntention, setEntranceIntention] = useState<'YES' | 'NO'>(entranceIntentionYn);

  const { mutate: patchArrivedStatus } = usePatchArrivedStatus(memberId, {
    onSuccess: () => {
      oneseoRefetch();
      editableRefetch();
    },
    onError: () => {
      setIsRealOneseoArrived((prev) => !prev);
    },
  });

  const { mutate: patchAgreeDocStatus } = usePatchAgreeDocStatus(memberId, {
    onSuccess: () => {
      oneseoRefetch();
      editableRefetch();
    },
    onError: () => {
      setEntranceIntention(entranceIntention === 'YES' ? 'NO' : 'YES');
    },
  });

  const { mutate: patchCompetencyScore } = usePatchCompetencyScore(memberId, {
    onSuccess: () => {
      oneseoRefetch();
      editableRefetch();
    },
  });
  const { mutate: patchInterviewScore } = usePatchInterviewScore(memberId, {
    onSuccess: () => {
      oneseoRefetch();
      editableRefetch();
    },
  });

  const { mutate: patchOneseoApproval } = usePatchOneseoApproval(memberId, {
    onSuccess: () => {
      oneseoRefetch();
      editableRefetch();
      toast.success('원서 수정 승인이 완료되었습니다.');
    },
    onError: () => {
      toast.error('원서 수정 승인에 실패했습니다.');
    },
  });

  const firstTestResult =
    firstTestPassYn === 'YES' ? '합격' : firstTestPassYn === 'NO' ? '불합격' : '미정';
  const secondTestResult =
    secondTestPassYn === 'YES' ? '합격' : secondTestPassYn === 'NO' ? '불합격' : '미정';

  const formatted역량검사점수 = formatScore(String(competencyEvaluationScore ?? ''));
  const formatted심층면접점수 = formatScore(String(interviewScore ?? ''));

  const { control, watch, setValue } = useForm({
    defaultValues: {
      역량검사점수: formatted역량검사점수,
      심층면접점수: formatted심층면접점수,
    },
  });

  const debounced역량검사점수 = useDebounce(watch('역량검사점수'), 1000);
  const debounced심층면접점수 = useDebounce(watch('심층면접점수'), 1000);

  useEffect(() => {
    const formatAndSetScore = (score: string, fieldName: '역량검사점수' | '심층면접점수') => {
      const formattedScore = formatScore(score);
      setValue(fieldName, formattedScore !== 'NaN' ? formattedScore : '');
    };

    formatAndSetScore(debounced역량검사점수, '역량검사점수');
    formatAndSetScore(debounced심층면접점수, '심층면접점수');
  }, [debounced역량검사점수, debounced심층면접점수, setValue]);

  const handleRealOneseoArrived = () => {
    setDocumentSubmissionChangeModal(false);
    patchArrivedStatus();
    setIsRealOneseoArrived((prev) => !prev);
  };

  const handleAgreeDocArrived = () => {
    const updatedIntention = entranceIntention === 'YES' ? 'NO' : 'YES';
    setEntranceIntention(updatedIntention);
    setAdmissionAgreementChangeModal(false);
    patchAgreeDocStatus({ entranceIntentionYn: updatedIntention });
  };

  const handleAptitudeScore = () => {
    const 역량검사점수 = parseFloat(watch('역량검사점수'));

    if (역량검사점수 < 0 || 역량검사점수 > 100 || isNaN(역량검사점수)) return;

    patchCompetencyScore({ competencyEvaluationScore: 역량검사점수 });
  };

  const handleInterviewScore = () => {
    const 심층면접점수 = parseFloat(watch('심층면접점수'));

    if (심층면접점수 < 0 || 심층면접점수 > 100 || isNaN(심층면접점수)) return;

    patchInterviewScore({ interviewScore: 심층면접점수 });
  };

  const handleOneseoEdit = () => {
    if (editableData?.oneseoEditability === true) {
      push(`/edit/${memberId}?step=1`);
    } else {
      setApplicationModificationNotPossibleModal(true);
    }
  };

  const handleOneseoPrint = () => {
    push(`/print/${memberId}`);
  };

  return (
    <TableRow className={cn('h-16', 'border-0', 'hover:bg-transparent')}>
      <TableCell className={cn('h-16', 'w-[100px]', 'p-4', 'text-zinc-900')}>
        {submitCode}
      </TableCell>
      <TableCell className={cn('h-16', 'w-[130px]', 'p-4')}>
        <Toggle
          onClick={() => setDocumentSubmissionChangeModal(true, handleRealOneseoArrived)}
          pressed={isRealOneseoArrived}
          icon={<CheckIcon />}
        >
          제출 완료
        </Toggle>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[154px]', 'p-4')}>
        <div className={cn('flex', 'flex-col')}>
          <span className={cn('text-sm', 'font-semibold', 'leading-5', 'text-zinc-900')}>
            {name}
          </span>
          <span className={cn('text-sm', 'font-normal', 'leading-5', 'text-zinc-600')}>
            {phoneNumber}
          </span>
        </div>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[154px]', 'p-4', 'text-zinc-600')}>
        {schoolName}
      </TableCell>
      <TableCell className={cn('h-16', 'w-[152px]', 'p-4', 'font-medium', 'text-zinc-900')}>
        {ScreeningEnum[screening]}
      </TableCell>
      <TableCell className={cn('h-16', 'w-[96px]', 'p-4')}>
        <Badge variant={firstTestResult}>{firstTestResult}</Badge>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[153px]', 'p-4', 'text-zinc-400')}>
        {firstTestPassYn === 'YES' && is역량검사처리기간 ? (
          <div className={cn('flex', 'gap-1.5')}>
            <Controller
              name="역량검사점수"
              control={control}
              render={({ field }) => <TextField {...field} disabled={!!secondTestPassYn} />}
            />
            <Button
              variant={
                watch('역량검사점수') && formatted역량검사점수 !== watch('역량검사점수')
                  ? 'default'
                  : 'subtitle'
              }
              onClick={handleAptitudeScore}
              disabled={!!secondTestPassYn}
            >
              저장
            </Button>
          </div>
        ) : (
          '진행 전'
        )}
      </TableCell>
      <TableCell className={cn('h-16', 'w-[153px]', 'p-4', 'text-zinc-400')}>
        {firstTestPassYn === 'YES' && is심층면접처리기간 ? (
          <div className={cn('flex', 'gap-1.5')}>
            <Controller
              name="심층면접점수"
              control={control}
              render={({ field }) => <TextField {...field} disabled={!!secondTestPassYn} />}
            />
            <Button
              variant={
                watch('심층면접점수') && formatted심층면접점수 !== watch('심층면접점수')
                  ? 'default'
                  : 'subtitle'
              }
              onClick={handleInterviewScore}
              disabled={!!secondTestPassYn}
            >
              저장
            </Button>
          </div>
        ) : (
          '진행 전'
        )}
      </TableCell>
      <TableCell className={cn('h-16', 'w-[96px]', 'p-4')}>
        <Badge variant={secondTestResult}>{secondTestResult}</Badge>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[170px]', 'p-4', 'text-center')}>
        <Toggle
          onClick={() => setAdmissionAgreementChangeModal(true, handleAgreeDocArrived)}
          pressed={entranceIntention === 'YES'}
          icon={<CheckIcon />}
          disabled={secondTestPassYn !== 'YES'}
        >
          제출 완료
        </Toggle>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[121px]', 'p-4', 'text-right')}>
        <Button onClick={handleOneseoPrint} variant="outline">
          원서 출력
        </Button>
      </TableCell>
      <TableCell className={cn('h-16', 'w-[121px]', 'p-4', 'text-right')}>
        {testResultTag === 'REQUEST' ? (
          <Button
            onClick={() => patchOneseoApproval()}
            variant={oneseoEditStatus === 'APPROVED' ? 'subtitle' : 'outline'}
            disabled={oneseoEditStatus === 'APPROVED'}
          >
            {oneseoEditStatus === 'REQUESTED' ? '원서 수정 승인' : '승인 완료'}
          </Button>
        ) : (
          <Button onClick={handleOneseoEdit} variant="outline">
            성적 수정
          </Button>
        )}
      </TableCell>
    </TableRow>
  );
};

export default ApplicantTR;

'use client';

import { useEffect, useState } from 'react';

import { useGetEditability, useGetOneseoList } from '@repo/api/hooks';
import { useDebounce } from '@repo/hooks';
import { OneseoEditStatusTag, OneseoListType, ScreeningType, YesNo } from '@repo/types';
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
  Table,
  TableBody,
  TableHeader,
} from '@repo/ui/shadcn';
import { cn } from '@repo/utils';

import { ApplicantTH, ApplicantTR, FilterBar, SideMenu } from '@/components';
import { SideBarType } from '@/schemas';

interface MainPageProps {
  initialData: OneseoListType | undefined;
  isAfterFirstResults: boolean;
  isAfterSecondResults: boolean;
  is역량검사처리기간: boolean;
  is심층면접처리기간: boolean;
}

const flexColStyle = ['flex', 'flex-col'] as const;

const PER_PAGE = 10;
const DEFAULT_TEST_RESULT_TAG = 'ALL';

const testResultTypeConvertor: { [key: string]: string } = {
  ALL: '전체 지원자 관리',
  REQUEST: '원서 수정 요청 관리',
  FIRST_PASS: '1차 전형 합격자 관리',
  FINAL_PASS: '최종 합격자 관리',
  FALL: '불합격자 관리',
};

const MainPage = ({
  initialData,
  isAfterFirstResults,
  isAfterSecondResults,
  is역량검사처리기간,
  is심층면접처리기간,
}: MainPageProps) => {
  const [isOpen, setIsOpen] = useState<boolean>(true);

  const [keyword, setKeyword] = useState<string>('');
  const [testResultTag, setTestResultTag] = useState<SideBarType>(DEFAULT_TEST_RESULT_TAG);
  const [isSubmitted, setIsSubmitted] = useState<YesNo | string>('');
  const [screeningTag, setScreeningTag] = useState<ScreeningType | string>('');
  const [requested, setRequested] = useState<OneseoEditStatusTag>('ANY_EDIT');
  const [page, setPage] = useState<number>(0);

  const debouncedKeyword = useDebounce(keyword, 1000);

  const { data, refetch: oneseoRefetch } = useGetOneseoList(
    {
      page: page,
      size: PER_PAGE,
      testResultTag: testResultTag === 'REQUEST' ? 'ALL' : testResultTag,
      screeningTag: screeningTag,
      isSubmitted: testResultTag === 'REQUEST' ? '' : isSubmitted,
      keyword: debouncedKeyword,
      status: testResultTag === 'REQUEST' ? requested : undefined,
    },
    {
      initialData: initialData,
    },
  );

  const { data: editableData, refetch: editableRefetch } = useGetEditability();

  const totalPages = data?.info.totalPages;

  const startPage = totalPages ? Math.max(0, Math.min(page, data.info.totalPages - 3)) : 0;

  const pageNumbers = totalPages
    ? Array.from(
        { length: Math.min(3, data.info.totalPages - startPage) },
        (_, i) => startPage + i + 1,
      )
    : [];

  useEffect(() => {
    oneseoRefetch();
  }, [debouncedKeyword, page, testResultTag, isSubmitted, screeningTag, requested]);

  useEffect(() => {
    setPage(0);
  }, [debouncedKeyword, testResultTag, isSubmitted, screeningTag, requested]);
  // 필터 조건이 변경 되었을때 1번부터 다시 시작

  return (
    <main
      className={cn([
        isOpen && 'ml-60',
        isOpen ? 'px-10' : 'pl-20 pr-10',
        'pt-[60px]',
        'pb-8',
        'bg-white',
      ])}
    >
      <SideMenu
        testResultTag={testResultTag}
        setTestResultTag={setTestResultTag}
        isOpen={isOpen}
        setIsOpen={setIsOpen}
      />
      <div className={cn([...flexColStyle, 'gap-8'])}>
        <h1 className={cn('text-gray-900', 'text-3xl', 'font-semibold')}>
          {testResultTypeConvertor[testResultTag]}
        </h1>
        <div className={cn([...flexColStyle, 'gap-5'])}>
          <FilterBar
            screeningTag={screeningTag}
            setScreeningTag={setScreeningTag}
            keyword={keyword}
            setKeyword={setKeyword}
            isSubmitted={isSubmitted}
            setIsSubmitted={setIsSubmitted}
            requested={requested}
            setRequested={setRequested}
            testResultTag={testResultTag}
            isAfterFirstResults={isAfterFirstResults}
            isAfterSecondResults={isAfterSecondResults}
          />
          <div
            className={cn(
              'border',
              'border-solid',
              'border-zinc-200',
              'w-full',
              'rounded-t-md',
              'overflow-hidden',
              'max-h-[calc(100vh-280px)]',
              'overflow-scroll',
            )}
          >
            <Table>
              <TableHeader>
                <ApplicantTH />
              </TableHeader>
              <TableBody>
                {data?.oneseos &&
                  data.oneseos.map((oneseo) => (
                    <ApplicantTR
                      {...oneseo}
                      key={oneseo.memberId}
                      editableData={editableData}
                      oneseoRefetch={oneseoRefetch}
                      editableRefetch={editableRefetch}
                      is역량검사처리기간={is역량검사처리기간}
                      is심층면접처리기간={is심층면접처리기간}
                      testResultTag={testResultTag}
                    />
                  ))}
              </TableBody>
            </Table>
          </div>

          {totalPages ? (
            <Pagination>
              <PaginationContent>
                <PaginationItem>
                  <PaginationPrevious
                    onClick={() => setPage((prev) => (prev > 0 ? prev - 1 : 0))}
                  />
                </PaginationItem>
                {pageNumbers.map((pageNumber: number) => (
                  <PaginationItem key={pageNumber}>
                    <PaginationLink
                      isActive={pageNumber - 1 === page}
                      onClick={() => setPage(pageNumber - 1)}
                    >
                      {pageNumber}
                    </PaginationLink>
                  </PaginationItem>
                ))}
                <PaginationItem>
                  <PaginationNext
                    onClick={() =>
                      setPage((prev) =>
                        prev < data.info.totalPages - 1 ? prev + 1 : data.info.totalPages - 1,
                      )
                    }
                  />
                </PaginationItem>
              </PaginationContent>
            </Pagination>
          ) : (
            <span className={cn('text-red-500')}>조회된 지원자 데이터가 없습니다.</span>
          )}
        </div>
      </div>
    </main>
  );
};

export default MainPage;
